(function() {
  const results = [];
  const h3s = document.querySelectorAll('h3');

  for (let h3 of h3s) {
    if (results.length >= 5) break;

    const title = h3.innerText;
    if (!title) continue;

    // Find the parent container
    let parent = h3.parentElement;
    while (parent && !parent.querySelector('a[href^="http"]')) {
      parent = parent.parentElement;
    }

    if (!parent) continue;

    // Get URL
    const linkElem = parent.querySelector('a[href^="http"]');
    const url = linkElem ? linkElem.href : '';

    // Get description - look for text following the URL
    let desc = '';
    const allText = parent.innerText;
    const lines = allText.split('\n');
    // Description is usually after the URL line
    for (let i = 0; i < lines.length; i++) {
      if (lines[i].includes('http') && lines[i+1]) {
        desc = lines[i+1];
        break;
      }
    }

    // Skip if it's an ad or special result
    if (url && url.length > 10 && !url.includes('youtube.com') && !url.includes('/maps') && title.length > 3) {
      results.push({ 
        title: title,
        url: url,
        description: desc
      });
    }
  }

  return results;
})()

(function() {
  const results = [];
  const h3s = document.querySelectorAll('h3');

  for (let h3 of h3s) {
    if (results.length >= 5) break;

    const title = h3.innerText.trim();
    if (!title || title.length < 3) continue;

    // Find parent container with link
    let parent = h3.parentElement;
    let depth = 0;
    while (parent && depth < 10) {
      const linkElem = parent.querySelector('a[href^="http"]');
      if (linkElem) {
        const url = linkElem.href;

        // Skip YouTube videos and ads
        if (url.includes('youtube.com') || url.includes('google.com/ads') || url.includes('google.com/maps')) {
          break;
        }

        // Get description - look for text element with decent length
        let desc = '';
        const textDivs = parent.querySelectorAll('div');
        for (let div of textDivs) {
          const text = div.innerText;
          if (text && text.length > 40 && text.length < 300 && !text.includes('http')) {
            desc = text;
            break;
          }
        }

        results.push({
          title: title,
          url: url,
          description: desc
        });
        break;
      }
      parent = parent.parentElement;
      depth++;
    }
  }

  return JSON.stringify(results, null, 2);
})()

