(function() {
  const results = [];
  const h3s = document.querySelectorAll('h3');

  for (let h3 of h3s) {
    if (results.length >= 5) break;

    const title = h3.innerText.trim();
    if (!title || title.length < 3) continue;

    // Find the result container - usually a parent with role or specific class
    let container = h3;
    while (container && container.tagName !== 'DIV') {
      container = container.parentElement;
    }

    // Go up to find the full result block
    let resultBlock = container;
    for (let i = 0; i < 5; i++) {
      if (resultBlock.parentElement) resultBlock = resultBlock.parentElement;
    }

    // Get the link
    const linkElem = resultBlock.querySelector('a[href^="http"]');
    if (!linkElem) continue;

    const url = linkElem.href;

    // Skip non-organic results
    if (url.includes('youtube.com') || url.includes('google.com/ads') || url.includes('/maps') || url.includes('/shopping')) {
      continue;
    }

    // Get description from the text after the URL
    let desc = '';
    const allDivs = resultBlock.querySelectorAll('div');
    let foundUrl = false;

    for (let div of allDivs) {
      const text = div.innerText;
      if (!text) continue;

      // Look for the greenish URL text
      if (text.includes('›') || (text.length < 100 && text.includes('.'))) {
        foundUrl = true;
        continue;
      }

      // Description comes after URL
      if (foundUrl && text.length > 40 && text.length < 300 && !text.includes('http')) {
        desc = text;
        break;
      }
    }

    results.push({
      title: title,
      url: url,
      description: desc
    });
  }

  return JSON.stringify(results, null, 2);
})()

